import{_ as s,c as t,o as n,a1 as e}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"クイックスタート: 5分で始めるPlannotator | Plannotator","description":"Plannotatorのインストールと設定方法を学びます。5分以内にCLIのインストール、Claude CodeまたはOpenCodeプラグインの設定を完了し、プランレビューとコードレビューのワークフローをマスターします。","frontmatter":{"title":"クイックスタート: 5分で始めるPlannotator | Plannotator","sidebarTitle":"5分で始める","subtitle":"クイックスタート：5分で始めるPlannotator","description":"Plannotatorのインストールと設定方法を学びます。5分以内にCLIのインストール、Claude CodeまたはOpenCodeプラグインの設定を完了し、プランレビューとコードレビューのワークフローをマスターします。","tags":["クイックスタート","入門","インストール","Claude Code","OpenCode"],"order":1},"headers":[],"relativePath":"ja/backnotprop/plannotator/start/getting-started/index.md","filePath":"ja/backnotprop/plannotator/start/getting-started/index.md"}'),o={name:"ja/backnotprop/plannotator/start/getting-started/index.md"};function l(i,a,p,r,d,c){return n(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="クイックスタート-5分で始めるplannotator" tabindex="-1">クイックスタート：5分で始めるPlannotator <a class="header-anchor" href="#クイックスタート-5分で始めるplannotator" aria-label="Permalink to &quot;クイックスタート：5分で始めるPlannotator&quot;">​</a></h1><h2 id="この章で学べること" tabindex="-1">この章で学べること <a class="header-anchor" href="#この章で学べること" aria-label="Permalink to &quot;この章で学べること&quot;">​</a></h2><ul><li>✅ Plannotatorのコア機能と使用シナリオを理解する</li><li>✅ 5分以内にPlannotatorのインストールを完了する</li><li>✅ Claude CodeまたはOpenCodeとの連携を設定する</li><li>✅ 初めてのプランレビューとコードレビューを実行する</li></ul><h2 id="現在の課題" tabindex="-1">現在の課題 <a class="header-anchor" href="#現在の課題" aria-label="Permalink to &quot;現在の課題&quot;">​</a></h2><p><strong>Plannotator</strong>は、Claude CodeとOpenCode向けに設計されたインタラクティブなレビューツールです。以下の課題を解決します：</p><p><strong>課題1</strong>：AIが生成した実装プランをターミナルで読むと、テキスト量が多く構造が不明瞭で、レビューが大変。</p><p><strong>課題2</strong>：AIにフィードバックを伝えたいとき、「3段落目を削除」「この関数を修正」などテキストで説明するしかなく、コミュニケーションコストが高い。</p><p><strong>課題3</strong>：コードレビュー時に複数のターミナルやIDEを開いて切り替える必要があり、集中しにくい。</p><p><strong>課題4</strong>：チームメンバーがレビューに参加したいが、プラン内容の共���方法がわからない。</p><p><strong>Plannotatorでできること</strong>：</p><ul><li>ビジュアルUIでターミナル閲覧を置き換え、構造を明確化</li><li>テキストを選択するだけでアノテーション（削除、置換、コメント）を追加し、正確なフィードバックが可能</li><li>Git diffのビジュアルレビュー、行レベルのアノテーションをサポート</li><li>URL共有機能でバックエンド不要のチームコラボレーション</li></ul><h2 id="こんなときに使う" tabindex="-1">こんなときに使う <a class="header-anchor" href="#こんなときに使う" aria-label="Permalink to &quot;こんなときに使う&quot;">​</a></h2><p><strong>適した使用シナリオ</strong>：</p><ul><li>Claude CodeまたはOpenCodeでAI支援開発を行っている</li><li>AIが生成した実装プランをレビューする必要がある</li><li>コード変更を審査する必要がある</li><li>チームメンバーとプランやコードレビュー結果を共有する必要がある</li></ul><p><strong>適さないシナリオ</strong>：</p><ul><li>純粋に手動でコードを書いている（AI生成プランを使用しない）</li><li>すでに完全なコードレビューフローがある（GitHub PRなど）</li><li>ビジュアルレビューツールが不要</li></ul><h2 id="コアコンセプト" tabindex="-1">コアコンセプト <a class="header-anchor" href="#コアコンセプト" aria-label="Permalink to &quot;コアコンセプト&quot;">​</a></h2><h3 id="plannotatorとは" tabindex="-1">Plannotatorとは <a class="header-anchor" href="#plannotatorとは" aria-label="Permalink to &quot;Plannotatorとは&quot;">​</a></h3><p><strong>Plannotator</strong>は、AI Coding Agent（Claude Code、OpenCode）向けに設計されたインタラクティブなレビューツールで、主に2つの機能を提供します：</p><ol><li><strong>プランレビュー</strong>：AIが生成した実装プランをビジュアルでレビューし、アノテーションの追加、承認または却下をサポート</li><li><strong>コードレビュー</strong>：Git diffをビジュアルでレビューし、行レベルのアノテーションと複数のビューモードをサポート</li></ol><h3 id="動作原理" tabindex="-1">動作原理 <a class="header-anchor" href="#動作原理" aria-label="Permalink to &quot;動作原理&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (プラン生成)   │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Plannotator   │  ← ローカルHTTPサーバー</span></span>
<span class="line"><span>│  (ビジュアルUI) │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  ブラウザ       │</span></span>
<span class="line"><span>│  (ユーザーレビュー) │</span></span>
<span class="line"><span>└─────────────────┘</span></span></code></pre></div><p><strong>コアフロー</strong>：</p><ol><li>AI Agentがプランまたはコード変更を完了</li><li>Plannotatorがローカルでサーバーを起動し、ブラウザを開く</li><li>ユーザーがブラウザでプラン/コードを確認し、アノテーションを追加</li><li>ユーザーが承認または却下し、PlannotatorがAI Agentに決定を返す</li><li>AI Agentがフィードバックに基づいて実装を続行または修正</li></ol><h3 id="セキュリティ" tabindex="-1">セキュリティ <a class="header-anchor" href="#セキュリティ" aria-label="Permalink to &quot;セキュリティ&quot;">​</a></h3><p><strong>すべてのデータはローカルで処理</strong>され、クラウドにアップロードされません：</p><ul><li>プラン内容、コードdiff、アノテーションはすべてローカルマシンに保存</li><li>ロー���ルHTTPサーバーはランダムポート（または固定ポート）を使用</li><li>URL共有機能はデータをURLハッシュに圧縮して実現、バックエンド不要</li></ul><h2 id="🎒-始める前の準備" tabindex="-1">🎒 始める前の準備 <a class="header-anchor" href="#🎒-始める前の準備" aria-label="Permalink to &quot;🎒 始める前の準備&quot;">​</a></h2><p><strong>システム要件</strong>：</p><ul><li>OS：macOS / Linux / Windows / WSL</li><li>ランタイム：Bun（インストールスクリプトが自動処理）</li><li>AI環境：Claude Code 2.1.7+ または OpenCode</li></ul><p><strong>インストール方��の選択</strong>：</p><ul><li>Claude Codeを使用する場合：CLI + プラグインのインストールが必要</li><li>OpenCodeを使用する場合：プラグインの設定が必要</li><li>コードレビューのみ行う場合：CLIのインストールのみ必要</li></ul><h2 id="ステップバイステップ" tabindex="-1">ステップバイステップ <a class="header-anchor" href="#ステップバイステップ" aria-label="Permalink to &quot;ステップバイステップ&quot;">​</a></h2><h3 id="ステップ1-plannotator-cliのインストール" tabindex="-1">ステップ1：Plannotator CLIのインストール <a class="header-anchor" href="#ステップ1-plannotator-cliのインストール" aria-label="Permalink to &quot;ステップ1：Plannotator CLIのインストール&quot;">​</a></h3><p><strong>macOS / Linux / WSL</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://plannotator.ai/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p><strong>Windows PowerShell</strong>：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">irm https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">plannotator.ai</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">install.ps1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> iex</span></span></code></pre></div><p><strong>Windows CMD</strong>：</p><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fsSL https://plannotator.ai/install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">o install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> del install.cmd</span></span></code></pre></div><p><strong>期待される結果</strong>：インストールスクリプトがPlannotator CLIを自動的にダウンロードしてシステムパスに追加し、バージョン番号（例：&quot;plannotator v0.6.7 installed to ...&quot;）が表示されます。</p><div class="tip custom-block"><p class="custom-block-title">インストールスクリプトの動作</p><p>インストールスクリプトは以下を実行します：</p><ol><li>最新バージョンのPlannotator CLIをダウンロード</li><li>システムパス（PATH）に追加</li><li>存在する可能性のある旧バージョンをクリーンアップ</li><li><code>/plannotator-review</code>コマンド（コードレビュー用）を自動インストール</li></ol></div><h3 id="ステップ2-claude-codeの設定-オプション" tabindex="-1">ステップ2：Claude Codeの設定（オプション） <a class="header-anchor" href="#ステップ2-claude-codeの設定-オプション" aria-label="Permalink to &quot;ステップ2：Claude Codeの設定（オプション）&quot;">​</a></h3><p>Claude Codeを使用する場合は、プラグインのインストールが必要です。</p><p><strong>Claude Codeで実行</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin marketplace add backnotprop/plannotator</span></span>
<span class="line"><span>/plugin install plannotator@plannotator</span></span></code></pre></div><p><strong>重要</strong>：プラグインインストール後、<strong>Claude Codeを再起動する必要があります</strong>。再起動しないとhookが有効になりません。</p><p><strong>期待される結果</strong>：プラグインのインストールが成功すると、Claude Codeのプラグインリストに<code>plannotator</code>が表示されます。</p><div class="info custom-block"><p class="custom-block-title">手動設定方法（オプション）</p><p>プラグインシステムを使用したくない場合は、hookを手動で設定できます。詳細は<a href="./../installation-claude-code/">Claude Codeプラグインのインストール</a>を参照してください。</p></div><h3 id="ステップ3-opencodeの設定-オプション" tabindex="-1">ステップ3：OpenCodeの設定（オプション） <a class="header-anchor" href="#ステップ3-opencodeの設定-オプション" aria-label="Permalink to &quot;ステップ3：OpenCodeの設定（オプション）&quot;">​</a></h3><p>OpenCodeを使用する場合は、<code>opencode.json</code>ファイルを編集する必要があります。</p><p><strong><code>opencode.json</code>を編集</strong>：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;$schema&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://opencode.ai/config.json&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@plannotator/opencode@latest&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>OpenCodeを再起動</strong>します。</p><p><strong>期待される結果</strong>：再起動後、OpenCodeが自動的にプラグインを読み込み、<code>submit_plan</code>ツールが使用可能になります。</p><h3 id="ステップ4-初めてのプランレビュー-claude-codeの例" tabindex="-1">ステップ4：初めてのプランレビュー（Claude Codeの例） <a class="header-anchor" href="#ステップ4-初めてのプランレビュー-claude-codeの例" aria-label="Permalink to &quot;ステップ4：初めてのプランレビュー（Claude Codeの例）&quot;">​</a></h3><p><strong>トリガー条件</strong>：Claude Codeに実装プランを生成させ、<code>ExitPlanMode</code>を呼び出します。</p><p><strong>会話例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ユーザー：ユーザー認証モジュールの実装プランを作成してください</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude：はい、実装プランです：</span></span>
<span class="line"><span>1. ユーザーモデルを作成</span></span>
<span class="line"><span>2. 登録APIを実装</span></span>
<span class="line"><span>3. ログインAPIを実装</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>（ExitPlanModeを呼び出し）</span></span></code></pre></div><p><strong>期待される結果</strong>：</p><ol><li>ブラウザが自動的にPlannotator UIを開く</li><li>AIが生成したプラン内容が表示される</li><li>プランテキストを選択してアノテーション（削除、置換、コメント）を追加できる</li><li>下部に「Approve」と「Request Changes」ボタンがある</li></ol><p><strong>操作</strong>：</p><ol><li>ブラウザでプランを確認</li><li>プランに問題がなければ、<strong>Approve</strong>をクリック → AIが実装を続行</li><li>修正が必要な場合、変更したいテキストを選択し、<strong>Delete</strong>、<strong>Replace</strong>、または<strong>Comment</strong>をクリック → <strong>Request Changes</strong>をクリック</li></ol><p><strong>期待される結果</strong>：クリック後、ブラウザが自動的に閉じ、Claude Codeがあなたの決定を受け取って実行を続けます。</p><h3 id="ステップ5-初めてのコードレビュー" tabindex="-1">ステップ5：初めてのコードレビュー <a class="header-anchor" href="#ステップ5-初めてのコードレビュー" aria-label="Permalink to &quot;ステップ5：初めてのコードレビュー&quot;">​</a></h3><p><strong>プロジェクトディレクトリで実行</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>期待される結果</strong>：</p><ol><li>ブラウザがコードレビューページを開く</li><li>Git diff（デフォルトは未コミットの変更）が表示される</li><li>左側にファイルツリー、右側にdiff viewerがある</li><li>行番号をクリックしてコード範囲を選択し、アノテーションを追加できる</li></ol><p><strong>操作</strong>：</p><ol><li>diff viewerでコード変更を確認</li><li>行番号をクリックしてレビューするコードを選択</li><li>右側のパネルでアノテーション（comment/suggestion/concern）を追加</li><li><strong>Send Feedback</strong>をクリックしてagentに送信、または<strong>LGTM</strong>をクリックして承認</li></ol><p><strong>期待される結果</strong>：Send Feedbackをクリックすると、ブラウザが閉じ、ター��ナルにフォーマットされたフィードバック内容が出力され、agentが自動的に処理します。</p><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><p>上記のステップを完了すると、以下ができるようになります：</p><ul><li>[ ] インストールスクリプトが &quot;plannotator vX.X.X installed to ...&quot; と表示される</li><li>[ ] Claude Codeでプランレビューをトリガーし、ブラウザが自動的にUIを開く</li><li>[ ] UIでプランテキストを選択し、アノテーションを追加できる</li><li>[ ] ApproveまたはRequest Changesをクリックし、ブラウザが閉じる</li><li>[ ] <code>/plannotator-review</code>を実行し、コードレビュー画面が表示される</li><li>[ ] コードレビューで行レベルのアノテーションを追加し、Send Feedbackをクリックできる</li></ul><p><strong>いずれかのステップで失敗した場合</strong>は、以下を参照：</p><ul><li><a href="./../installation-claude-code/">Claude Codeインストールガイド</a></li><li><a href="./../installation-opencode/">OpenCodeインストールガイド</a></li><li><a href="./../../faq/common-problems/">よくある質問</a></li></ul><h2 id="よくあるトラブル" tabindex="-1">よくあるトラブル <a class="header-anchor" href="#よくあるトラブル" aria-label="Permalink to &quot;よくあるトラブル&quot;">​</a></h2><p><strong>よくあるエラー1</strong>：インストール後に<code>plannotator</code>を実行すると&quot;command not found&quot;と表示される</p><p><strong>原因</strong>：PATH環境変数が更新されていない、またはターミナルの再起動が必要。</p><p><strong>解決方法</strong>：</p><ul><li>macOS/Linux：<code>source ~/.zshrc</code>または<code>source ~/.bashrc</code>を実行、またはターミナルを再起動</li><li>Windows：PowerShellまたはCMDを再起動</li></ul><p><strong>よくあるエラー2</strong>：Claude Codeでプラグインをインストール後、プランレビューがトリガーされない</p><p><strong>原因</strong>：Claude Codeを再起動していないため、hookが有効になっていない。</p><p><strong>解決方法</strong>：Claude Codeを完全に終了（ウィンドウを閉じるだけでなく）してから、再度開く。</p><p><strong>よくあるエラー3</strong>：ブラウザが自動的に開かない</p><p><strong>原因</strong>：リモートモード（devcontainer、SSHなど）の可能性、またはポートが使用中。</p><p><strong>解決方法</strong>：</p><ul><li><code>PLANNOTATOR_REMOTE=1</code>環境変数が設定されているか確認</li><li>ターミナルに出力されたURLを確認し、手動でブラウザで開く</li><li>詳細は<a href="./../../advanced/remote-mode/">リモート/Devcontainerモード</a>を参照</li></ul><p><strong>よくあるエラー4</strong>：コードレビューで&quot;No changes&quot;と表示される</p><p><strong>原因</strong>：現在、未コミットのgit変更がない。</p><p><strong>解決方法</strong>：</p><ul><li>まず<code>git status</code>を実行して変更があることを確認</li><li>または<code>git add</code>でいくつかのファイルをステージング</li><li>または他のdiffタイプ（last commitなど）に切り替え</li></ul><h2 id="この章のまとめ" tabindex="-1">この章のまとめ <a class="header-anchor" href="#この章のまとめ" aria-label="Permalink to &quot;この章のまとめ&quot;">​</a></h2><p>Plannotatorは、ローカルで動作するレビューツールで、ビジュアルUIによりプランレビューとコードレビューの効率を向上させます：</p><p><strong>コア機能</strong>：</p><ul><li><strong>プランレビュー</strong>：AIが生成したプランをビジュアルでレビュー、正確なアノテーションをサポート</li><li><strong>コードレビュー</strong>：Git diffをビジュアルでレビュー、行レベルのアノテーションをサポート</li><li><strong>URL共有</strong>：バックエンド不要でレビュー内容を共有</li><li><strong>サードパーティ連携</strong>：承認されたプランをObsidian/Bearに自動保存</li></ul><p><strong>主なメリット</strong>：</p><ul><li>ローカル実行でデータセキュリティを確保</li><li>ビジュアルUIで効率向上</li><li>正確なフィードバックでコミュニケーションコストを削減</li><li>アカウントシステム不要でチームコラボレーション</li></ul><h2 id="次の章の予告" tabindex="-1">次の章の予告 <a class="header-anchor" href="#次の章の予告" aria-label="Permalink to &quot;次の章の予告&quot;">​</a></h2><blockquote><p>次の章では**<a href="./../installation-claude-code/">Claude Codeプラグインのインストール</a>**を学びます。</p><p>学べる内容：</p><ul><li>Claude Codeプラグインの詳細なインストール手順</li><li>hookを手動で設定する方法</li><li>インストールが成功したかの確認方法</li><li>よくあるインストール問題の解決方法</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>CLIエントリ（プランレビュー）</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L1-L50" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></td><td>1-50</td></tr><tr><td>CLIエントリ（コードレビュー）</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L46-L84" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></td><td>46-84</td></tr><tr><td>プランレビューサーバー</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L1-L200" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>1-200</td></tr><tr><td>コードレビューサーバー</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/review.ts#L1-L150" target="_blank" rel="noreferrer"><code>packages/server/review.ts</code></a></td><td>1-150</td></tr><tr><td>Gitツール</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L1-L100" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>1-100</td></tr><tr><td>プランレビューUI</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>1-200</td></tr><tr><td>コードレビューUI</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></td><td>1-200</td></tr></tbody></table><p><strong>主要な定数</strong>：</p><ul><li><code>MAX_RETRIES = 5</code>：ポートリトライ回数（<code>packages/server/index.ts:80</code>）</li><li><code>RETRY_DELAY_MS = 500</code>：ポートリトライ遅延（<code>packages/server/index.ts:80</code>）</li></ul><p><strong>主要な関数</strong>：</p><ul><li><code>startPlannotatorServer()</code>：プランレビューサーバーを起動（<code>packages/server/index.ts</code>）</li><li><code>startReviewServer()</code>：コードレビューサーバーを起動（<code>packages/server/review.ts</code>）</li><li><code>runGitDiff()</code>：git diffコマンドを実行（<code>packages/server/git.ts</code>）</li></ul><p><strong>環境変数</strong>：</p><ul><li><code>PLANNOTATOR_REMOTE</code>：リモートモードフラグ（<code>apps/hook/server/index.ts:17</code>）</li><li><code>PLANNOTATOR_PORT</code>：固定ポート（<code>apps/hook/server/index.ts:18</code>）</li><li><code>PLANNOTATOR_BROWSER</code>：カスタムブラウザ（<code>apps/hook/README.md:79</code>）</li><li><code>PLANNOTATOR_SHARE</code>：URL共有スイッチ（<code>apps/hook/server/index.ts:44</code>）</li></ul></details>`,104)])])}const u=s(o,[["render",l]]);export{g as __pageData,u as default};
